#[cfg(test)]
mod tests {
    use super::*;
    use backbone_core::state_machine::StateMachineBehavior;

    #[test]
    fn test_initial_state() {
        let sm = UserQuotaStateMachine::default();
        assert_eq!(sm.current_state(), UserQuotaState::Normal);
        assert!(sm.current_state().is_initial());
    }

    #[test]
    fn test_valid_transition() {
        let mut sm = UserQuotaStateMachine { current_state: UserQuotaState::Normal };
        assert!(sm.can_transition(UserQuotaTransition::Exceed));
        let result = sm.transition(UserQuotaTransition::Exceed);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), UserQuotaState::Exceeded);
    }

    #[test]
    fn test_invalid_transition() {
        let mut sm = UserQuotaStateMachine { current_state: UserQuotaState::Normal };
        // Restore is not valid from Normal state
        let result = sm.transition(UserQuotaTransition::Restore);
        assert!(result.is_err());
    }

    #[test]
    fn test_state_parsing() {
        let state: UserQuotaState = "normal".parse().unwrap();
        assert_eq!(state, UserQuotaState::Normal);
    }

    #[test]
    fn test_available_transitions() {
        let sm = UserQuotaStateMachine::default();
        let available = sm.available_transitions();
        // Should have at least some transitions available from initial state
        assert!(!available.is_empty() || sm.current_state().is_final());
    }
}
